    const title = EF.ui.h('div', 'ef-settings-provider-title')
    title.appendChild(EF.ui.h('span', null, { text: meta.label || meta.id }))
    head.appendChild(title)
    const status = EF.ui.h('div', 'ef-settings-provider-status')
